2199	[B-naturality of the stalk--tensor comparison]
2200	  \label{lem:stalk_tensor_commutation_naturality_right}
2201	  % \lean: TODO placeholder per DAG integrity rule 1. As the NOTE above records,
2202	  % no standalone decl exists (the B-naturality content was inlined into
2203	  % PresheafOfModules.isLocallyInjective_whiskerLeft_of_W); the placeholder keeps
2204	  % the node rule-1 compliant without falsely claiming a real declaration.
2205	  \lean{AlgebraicGeometry.TODO.stalk_tensor_commutation_naturality_right}
2206	  \uses{lem:stalk_tensor_commutation, lem:stalk_linear_map}
2207	  Let \(R\), \(A\) and \(x \in X\) be as in \cref{lem:stalk_tensor_commutation}, and let
2208	  \(g : M \to N\) be a morphism of presheaves of \(R\)-modules. The isomorphism
2209	  \(\mathtt{stalkTensorIso}\) of \cref{lem:stalk_tensor_commutation} is natural in the
2210	  \emph{second} tensor factor: the square
2211	  \[
2212	    \begin{array}{ccc}
2213	      (A \otimes^{p} M).\mathtt{stalk}\,x
2214	        & \xrightarrow{\ (A \triangleleft g)_x\ }
2215	        & (A \otimes^{p} N).\mathtt{stalk}\,x \\[4pt]
2216	      \big\downarrow{\scriptstyle \mathtt{stalkTensorIso}\,A\,M}
2217	        & & \big\downarrow{\scriptstyle \mathtt{stalkTensorIso}\,A\,N} \\[4pt]
2218	      A_x \otimes_{R_x} M_x
2219	        & \xrightarrow{\ \mathrm{id}_{A_x} \otimes\, g_x\ }
2220	        & A_x \otimes_{R_x} N_x
2221	    \end{array}
2222	  \]
2223	  commutes, where \(g_x\) is the \(R_x\)-linear stalk map of
2224	  \cref{lem:stalk_linear_map} and \(\mathrm{id}_{A_x} \otimes\, g_x =
2225	  \mathtt{LinearMap.lTensor}\,A_x\,g_x\). Equivalently, under \(\mathtt{stalkTensorIso}\)
2226	  the stalk of the left-whiskered morphism \(A \triangleleft g = \mathrm{id}_A \otimes g\)
2227	  is identified with \(\mathtt{LinearMap.lTensor}\,A_x\,(\mathtt{stalkLinearMap}\,g\,x)\).
2228	\end{lemma}
2229	
2230	\begin{proof}
2231	  \uses{lem:stalk_tensor_commutation, lem:stalk_linear_map}
2232	  Both composites in the square are \(R_x\)-linear maps out of
2233	  \((A \otimes^{p} M).\mathtt{stalk}\,x\), so by \(\mathtt{TensorProduct.induction\_on}\)
2234	  together with the joint epimorphy of the germ maps \(\mathtt{stalk\_hom\_ext}\) it
2235	  suffices to check that they agree on germs of simple tensors
2236	  \(\mathrm{germ}_x(a \otimes m)\), with \(a \in A(U)\) and \(m \in M(U)\). On such a
2237	  generator the left-then-bottom composite sends \(\mathrm{germ}_x(a \otimes m)\) first
2238	  to \(\mathrm{germ}_x a \otimes \mathrm{germ}_x m\) by the germ characterisation
2239	  \(\mathtt{stalkTensorLinearMap\_germ\_tmul}\) of \(\mathtt{stalkTensorIso}\,A\,M\)
2240	  (stage (iii) of \cref{lem:stalk_tensor_commutation}), and then to
2241	  \(\mathrm{germ}_x a \otimes g_x(\mathrm{germ}_x m)\) by definition of
2242	  \(\mathtt{LinearMap.lTensor}\). The germ--functoriality characterisation
2243	  \(\mathtt{stalkLinearMap\_germ}\) of \cref{lem:stalk_linear_map} gives
2244	  \(g_x(\mathrm{germ}_x m) = \mathrm{germ}_x(g_U\,m)\), so this equals
2245	  \(\mathrm{germ}_x a \otimes \mathrm{germ}_x(g_U\,m)\). The top-then-right composite
2246	  sends \(\mathrm{germ}_x(a \otimes m)\) first to
2247	  \(\mathrm{germ}_x\bigl((A \triangleleft g)_U(a \otimes m)\bigr) =
2248	  \mathrm{germ}_x(a \otimes g_U\,m)\) --- the whiskered map acts as
2249	  \(\mathrm{id}_A \otimes g\) sectionwise --- and then, again by
2250	  \(\mathtt{stalkTensorLinearMap\_germ\_tmul}\) for \(\mathtt{stalkTensorIso}\,A\,N\),
2251	  to \(\mathrm{germ}_x a \otimes \mathrm{germ}_x(g_U\,m)\). The two results agree, and
2252	  the inverse direction (the analogous identity for the reverse map
2253	  \(\mathtt{stalkTensorRev}\) via \(\mathtt{stalkTensorRev\_germ\_tmul}\)) is checked the
2254	  same way. Hence the square commutes.
2255	\end{proof}
