2260	[Unconditional left-whiskering of the localizer, via d.2]
2261	  \label{lem:islocallyinjective_whiskerleft_via_stalk}
2262	  \lean{PresheafOfModules.isLocallyInjective_whiskerLeft_of_W}
2263	  \uses{def:scheme_modules_tensorobj, lem:stalk_tensor_commutation, lem:stalk_linear_map}
2264	  Let \(R\), \(J\) be as above with \(J.\mathtt{WEqualsLocallyBijective}\,\mathtt{Ab}\),
2265	  let \(F\) be an \emph{arbitrary} presheaf of \(R\)-modules, and let \(g : M \to N\)
2266	  be a morphism whose underlying morphism lies in \(J.W\). Then the left-whiskered
2267	  morphism \(F \triangleleft g = \mathrm{id}_F \otimes g\) is \(J\)-locally injective
2268	  (indeed lies in \(J.W\)). No flatness and no local-triviality hypothesis on \(F\) is
2269	  required. This discharges the open left-whiskering obligation
2270	  \cref{lem:islocallyinjective_whisker_of_W} that the unconditional associator
2271	  \cref{lem:tensorobj_assoc_iso} consumes.
2272	\end{lemma}
