45	\section{The structure sheaf of a \(\Spec k\)-scheme as a sheaf of \(k\)-modules}
46	\label{sec:scheme_toModuleKSheaf}
47	
48	This section provides the substantive content of Phase~A step~5. For \(C\) a scheme over \(\Spec k\), the structure morphism \(C \to \Spec k\) induces an algebra map \(k \to \Gamma(C, U)\) for every open \(U \subseteq C\). This equips the structure sheaf with a sheaf-of-\(k\)-modules structure.
49	
50	\subsection{The algebra map from the structure morphism}
51	
52	For each open \(U \subseteq C\), the structure morphism induces a chain of ring maps
53	\[
54	  k \xrightarrow{\cong} \Gamma(\Spec k, \top) \xrightarrow{C.\mathrm{hom}} \Gamma(C, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C, U),
55	\]
56	where \(\rho\) is the restriction along \(U \le C.\mathrm{hom}^{-1}\top = \top\).
57	
58	\begin{definition}\leanok
59	[Algebra map on a section]
60	  \label{def:Scheme_kToSection}
61	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
62	  
63	  Let \(k\) be a commutative ring and \(C\) a scheme over \(\Spec k\). For any open \(U\) of \(C\), define the ring map \(k \to \Gamma(C, U)\) to be the composition of the inverse of the canonical isomorphism \(\Gamma(\Spec k, \top) \cong k\), the structure morphism map on global sections, and the restriction from \(\top\) to \(U\).
64	\end{definition}
